import{_ as d,o as e,c as o,aj as r}from"./chunks/framework.DpVzuYkC.js";const _=JSON.parse('{"title":"Static Web Server","description":"","frontmatter":{},"headers":[],"relativePath":"static-web-server/index.md","filePath":"static-web-server/README.md"}'),a={name:"static-web-server/index.md"};function c(h,t,E,R,l,i){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="static-web-server" tabindex="-1">Static Web Server <a class="header-anchor" href="#static-web-server" aria-label="Permalink to “Static Web Server”">​</a></h1><p><a href="https://static-web-server.net/" target="_blank" rel="noreferrer">Office Web</a> - <a href="https://github.com/static-web-server/static-web-server/" target="_blank" rel="noreferrer">Source</a> - <a href="https://ghcr.io/static-web-server/static-web-server" target="_blank" rel="noreferrer">Docker Image</a> - <a href="https://static-web-server.net/configuration/environment-variables/" target="_blank" rel="noreferrer">Document</a></p><hr><blockquote><p><a href="https://static-web-server.net/" target="_blank" rel="noreferrer">Static Web Server</a>（或 SWS 缩写）是一种小型且快速的生产就绪型 Web 服务器，适用于提供静态 Web 文件或资产。</p></blockquote><p>它专注于轻量级和易于使用的原则，同时保持由 Rust 编程语言提供支持的高性能和安全性。</p><p>它基于 Hyper 和 Tokio 运行时编写，提供并发和异步网络功能以及最新的 HTTP/1 - HTTP/2 实现。</p><p>跨平台，适用于 Linux、macOS、Windows、FreeBSD、NetBSD、Android、Docker 和 Wasm（通过 Wasmer）。</p><h2 id="环境变量" tabindex="-1">环境变量 <a class="header-anchor" href="#环境变量" aria-label="Permalink to “环境变量”">​</a></h2><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>环境变量与命令行参数等效，命令行参数优先级更高。 完整文档请参考 <a href="https://static-web-server.net/configuration/environment-variables/" target="_blank" rel="noreferrer">官方文档</a></p></div><h3 id="自定义变量" tabindex="-1">自定义变量 <a class="header-anchor" href="#自定义变量" aria-label="Permalink to “自定义变量”">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>TZ</code></td><td>时区设置</td><td><code>Asia/Shanghai</code></td></tr><tr><td><code>SERV_PORT</code></td><td>宿主机端口映射</td><td><code>80</code></td></tr></tbody></table><h3 id="服务器基础" tabindex="-1">服务器基础 <a class="header-anchor" href="#服务器基础" aria-label="Permalink to “服务器基础”">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>SERVER_HOST</code></td><td>监听地址 (如 <code>127.0.0.1</code> 或 <code>::1</code>)</td><td><code>[::]</code></td></tr><tr><td><code>SERVER_PORT</code></td><td>监听端口</td><td><code>80</code></td></tr><tr><td><code>SERVER_ROOT</code></td><td>静态文件根目录</td><td><code>./public</code></td></tr><tr><td><code>SERVER_INDEX_FILES</code></td><td>索引文件列表，按顺序匹配</td><td><code>index.html</code></td></tr><tr><td><code>SERVER_GRACE_PERIOD</code></td><td>优雅关闭等待时间 (秒，最大 255)</td><td><code>0</code></td></tr><tr><td><code>SERVER_CONFIG_FILE</code></td><td>TOML 配置文件路径</td><td><code>./sws.toml</code></td></tr></tbody></table><h3 id="unix-socket" tabindex="-1">Unix Socket <a class="header-anchor" href="#unix-socket" aria-label="Permalink to “Unix Socket”">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>SERVER_UNIX_SOCKET</code></td><td>Unix Domain Socket 路径 (替代 TCP)</td><td>空 (禁用)</td></tr><tr><td><code>SERVER_UNIX_SOCKET_MODE</code></td><td>Socket 文件权限 (八进制，如 <code>660</code>)</td><td>umask</td></tr><tr><td><code>SERVER_UNIX_SOCKET_FORCE</code></td><td>强制覆盖已有 Socket 文件</td><td><code>false</code></td></tr></tbody></table><h3 id="工作线程" tabindex="-1">工作线程 <a class="header-anchor" href="#工作线程" aria-label="Permalink to “工作线程”">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>SERVER_THREADS_MULTIPLIER</code></td><td>工作线程倍数 (CPU 数 × n)</td><td><code>1</code></td></tr><tr><td><code>SERVER_MAX_BLOCKING_THREADS</code></td><td>最大阻塞线程数</td><td><code>512</code></td></tr></tbody></table><h3 id="日志" tabindex="-1">日志 <a class="header-anchor" href="#日志" aria-label="Permalink to “日志”">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>SERVER_LOG_LEVEL</code></td><td>日志级别 (<code>error</code>, <code>warn</code>, <code>info</code>, <code>debug</code>, <code>trace</code>)</td><td><code>error</code></td></tr><tr><td><code>SERVER_LOG_FORMAT</code></td><td>日志格式 (<code>json</code>, <code>pretty</code>)</td><td><code>json</code></td></tr><tr><td><code>SERVER_LOG_WITH_ANSI</code></td><td>启用 ANSI 颜色 (仅 <code>pretty</code> 格式)</td><td><code>false</code></td></tr><tr><td><code>SERVER_LOG_FILE</code></td><td>日志文件路径 (追加写入)</td><td>空 (禁用)</td></tr><tr><td><code>SERVER_LOG_REMOTE_ADDRESS</code></td><td>记录远程地址</td><td><code>false</code></td></tr><tr><td><code>SERVER_LOG_X_REAL_IP</code></td><td>记录 X-Real-IP 头</td><td><code>false</code></td></tr><tr><td><code>SERVER_LOG_FORWARDED_FOR</code></td><td>记录 X-Forwarded-For 头</td><td><code>false</code></td></tr><tr><td><code>SERVER_TRUSTED_PROXIES</code></td><td>信任的代理 IP 列表 (逗号分隔)</td><td><code>&quot;&quot;</code></td></tr></tbody></table><h3 id="错误页面" tabindex="-1">错误页面 <a class="header-anchor" href="#错误页面" aria-label="Permalink to “错误页面”">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>SERVER_ERROR_PAGE_404</code></td><td>404 错误页面路径</td><td><code>./404.html</code></td></tr><tr><td><code>SERVER_ERROR_PAGE_50X</code></td><td>50x 错误页面路径</td><td><code>./50x.html</code></td></tr><tr><td><code>SERVER_FALLBACK_PAGE</code></td><td>回退页面路径 (用于客户端路由)</td><td>空 (禁用)</td></tr></tbody></table><h3 id="tls-http2" tabindex="-1">TLS / HTTP2 <a class="header-anchor" href="#tls-http2" aria-label="Permalink to “TLS / HTTP2”">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>SERVER_TLS</code></td><td>启用 TLS/HTTPS</td><td><code>false</code></td></tr><tr><td><code>SERVER_TLS_CERT</code></td><td>TLS 证书路径</td><td>空 (禁用)</td></tr><tr><td><code>SERVER_TLS_KEY</code></td><td>TLS 私钥路径</td><td>空 (禁用)</td></tr><tr><td><code>SERVER_HTTP2</code></td><td>启用 HTTP/2 (需先启用 TLS)</td><td><code>false</code></td></tr></tbody></table><h3 id="https-重定向" tabindex="-1">HTTPS 重定向 <a class="header-anchor" href="#https-重定向" aria-label="Permalink to “HTTPS 重定向”">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>SERVER_HTTPS_REDIRECT</code></td><td>HTTP 重定向到 HTTPS (需启用 TLS)</td><td><code>false</code></td></tr><tr><td><code>SERVER_HTTPS_REDIRECT_HOST</code></td><td>HTTPS 主机名或 IP</td><td><code>localhost</code></td></tr><tr><td><code>SERVER_HTTPS_REDIRECT_FROM_PORT</code></td><td>HTTP 重定向监听端口</td><td><code>80</code></td></tr><tr><td><code>SERVER_HTTPS_REDIRECT_FROM_HOSTS</code></td><td>允许重定向的主机列表</td><td><code>localhost</code></td></tr></tbody></table><h3 id="cors" tabindex="-1">CORS <a class="header-anchor" href="#cors" aria-label="Permalink to “CORS”">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>SERVER_CORS_ALLOW_ORIGINS</code></td><td>允许的来源列表 (<code>*</code> 表示全部)</td><td>空 (禁用)</td></tr><tr><td><code>SERVER_CORS_ALLOW_HEADERS</code></td><td>允许的请求头</td><td><code>origin, content-type, authorization</code></td></tr><tr><td><code>SERVER_CORS_EXPOSE_HEADERS</code></td><td>暴露的响应头</td><td><code>origin, content-type</code></td></tr></tbody></table><h3 id="压缩" tabindex="-1">压缩 <a class="header-anchor" href="#压缩" aria-label="Permalink to “压缩”">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>SERVER_COMPRESSION</code></td><td>启用 Gzip/Deflate/Brotli/Zstd 压缩</td><td><code>true</code></td></tr><tr><td><code>SERVER_COMPRESSION_LEVEL</code></td><td>压缩级别 (<code>fastest</code>, <code>default</code>, <code>best</code>)</td><td><code>default</code></td></tr><tr><td><code>SERVER_COMPRESSION_STATIC</code></td><td>直接提供预压缩文件 (.gz/.br/.zst)</td><td><code>true</code></td></tr></tbody></table><h3 id="目录列表" tabindex="-1">目录列表 <a class="header-anchor" href="#目录列表" aria-label="Permalink to “目录列表”">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>SERVER_DIRECTORY_LISTING</code></td><td>启用目录列表</td><td><code>false</code></td></tr><tr><td><code>SERVER_DIRECTORY_LISTING_ORDER</code></td><td>排序方式 (0-5，见下方说明)</td><td><code>6</code></td></tr><tr><td><code>SERVER_DIRECTORY_LISTING_FORMAT</code></td><td>列表格式 (<code>html</code>, <code>json</code>)</td><td><code>html</code></td></tr><tr><td><code>SERVER_DIRECTORY_LISTING_DOWNLOAD</code></td><td>启用下载格式 (<code>targz</code>)</td><td>空 (禁用)</td></tr></tbody></table><blockquote><p>排序代码：<code>0</code> Name升序, <code>1</code> Name降序, <code>2</code> 时间升序, <code>3</code> 时间降序, <code>4</code> 大小升序, <code>5</code> 大小降序, <code>6</code> 无序</p></blockquote><h3 id="安全与缓存" tabindex="-1">安全与缓存 <a class="header-anchor" href="#安全与缓存" aria-label="Permalink to “安全与缓存”">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>SERVER_SECURITY_HEADERS</code></td><td>启用安全头 (需启用 TLS)</td><td><code>true</code></td></tr><tr><td><code>SERVER_CACHE_CONTROL_HEADERS</code></td><td>启用缓存控制头</td><td><code>true</code></td></tr><tr><td><code>SERVER_ETAG</code></td><td>启用 ETag 和条件请求</td><td><code>true</code></td></tr><tr><td><code>SERVER_BASIC_AUTH</code></td><td>Basic 认证 (<code>user-id:password</code>，BCrypt)</td><td>空 (禁用)</td></tr></tbody></table><h3 id="行为控制" tabindex="-1">行为控制 <a class="header-anchor" href="#行为控制" aria-label="Permalink to “行为控制”">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>SERVER_REDIRECT_TRAILING_SLASH</code></td><td>目录 URI 尾斜杠重定向 (308)</td><td><code>true</code></td></tr><tr><td><code>SERVER_INCLUDE_HIDDEN</code></td><td>包含隐藏文件 (dotfiles)</td><td><code>false</code></td></tr><tr><td><code>SERVER_FOLLOW_SYMLINKS</code></td><td>跟随符号链接</td><td><code>false</code></td></tr><tr><td><code>SERVER_ACCEPT_MARKDOWN</code></td><td>Markdown 内容协商</td><td><code>false</code></td></tr><tr><td><code>SERVER_TEXT_CHARSET</code></td><td>文本响应默认 charset</td><td><code>true</code></td></tr></tbody></table><h3 id="健康检查与指标" tabindex="-1">健康检查与指标 <a class="header-anchor" href="#健康检查与指标" aria-label="Permalink to “健康检查与指标”">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>SERVER_HEALTH</code></td><td>启用 <code>/health</code> 端点</td><td><code>false</code></td></tr><tr><td><code>SERVER_METRICS</code></td><td>启用 Prometheus <code>/metrics</code> 端点</td><td><code>false</code></td></tr></tbody></table><h3 id="维护模式" tabindex="-1">维护模式 <a class="header-anchor" href="#维护模式" aria-label="Permalink to “维护模式”">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>SERVER_MAINTENANCE_MODE</code></td><td>启用维护模式</td><td><code>false</code></td></tr><tr><td><code>SERVER_MAINTENANCE_MODE_STATUS</code></td><td>维护模式 HTTP 状态码</td><td><code>503</code></td></tr><tr><td><code>SERVER_MAINTENANCE_MODE_FILE</code></td><td>维护模式 HTML 文件</td><td>空 (默认消息)</td></tr></tbody></table><h3 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to “Windows”">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><code>SERVER_WINDOWS_SERVICE</code></td><td>以 Windows 服务运行</td><td><code>false</code></td></tr></tbody></table>',42)])])}const S=d(a,[["render",c]]);export{_ as __pageData,S as default};
